const body = $input.first().json.body || $input.first().json;
const tenantId = body.tenantId;

if (!tenantId) {
  return { error: 'tenantId requis', sql: '' };
}

function esc(v) {
  return v == null ? 'NULL' : "'" + String(v).replace(/'/g, "''") + "'";
}

const templates = [
  {
    nom: 'Bienvenue',
    sujet: 'Bienvenue chez {{entreprise}} !',
    categorie: 'bienvenue',
    variables: ['prenom', 'entreprise', 'lien_espace'],
    contenuHtml: '<div style="font-family:\'Segoe UI\',Arial,sans-serif;max-width:600px;margin:0 auto;background:#ffffff;border-radius:8px;overflow:hidden;"><div style="background:linear-gradient(135deg,#2563eb,#1d4ed8);padding:40px 30px;text-align:center;"><h1 style="color:#ffffff;margin:0;font-size:28px;">Bienvenue !</h1></div><div style="padding:30px;"><p style="color:#374151;font-size:16px;line-height:1.6;">Bonjour {{prenom}},</p><p style="color:#374151;font-size:16px;line-height:1.6;">Nous sommes ravis de vous accueillir chez <strong>{{entreprise}}</strong>. Votre compte est maintenant actif et pret a utiliser.</p><div style="text-align:center;margin:30px 0;"><a href="{{lien_espace}}" style="display:inline-block;padding:14px 32px;background:#2563eb;color:#ffffff;text-decoration:none;border-radius:8px;font-weight:600;font-size:16px;">Acceder a mon espace</a></div><p style="color:#6b7280;font-size:14px;line-height:1.6;">Si vous avez des questions, n\'hesitez pas a nous contacter. Nous sommes la pour vous aider.</p></div><div style="background:#f9fafb;padding:20px 30px;text-align:center;border-top:1px solid #e5e7eb;"><p style="color:#9ca3af;font-size:12px;margin:0;">{{entreprise}} — Cet email a ete envoye automatiquement</p></div></div>',
    contenuText: 'Bonjour {{prenom}},\n\nBienvenue chez {{entreprise}} ! Votre compte est actif.\n\nAccedez a votre espace : {{lien_espace}}\n\nCordialement,\n{{entreprise}}'
  },
  {
    nom: 'Newsletter mensuelle',
    sujet: 'Les actualites du mois — {{entreprise}}',
    categorie: 'newsletter',
    variables: ['prenom', 'entreprise', 'mois', 'contenu_principal', 'lien_desabonnement'],
    contenuHtml: '<div style="font-family:\'Segoe UI\',Arial,sans-serif;max-width:600px;margin:0 auto;background:#ffffff;border-radius:8px;overflow:hidden;"><div style="background:#1e293b;padding:30px;text-align:center;"><h1 style="color:#ffffff;margin:0;font-size:24px;">Newsletter {{mois}}</h1><p style="color:#94a3b8;margin:8px 0 0;font-size:14px;">{{entreprise}}</p></div><div style="padding:30px;"><p style="color:#374151;font-size:16px;line-height:1.6;">Bonjour {{prenom}},</p><p style="color:#374151;font-size:16px;line-height:1.6;">Voici les dernieres actualites de ce mois.</p><div style="margin:20px 0;padding:20px;background:#f8fafc;border-left:4px solid #2563eb;border-radius:0 8px 8px 0;"><p style="color:#374151;font-size:15px;line-height:1.6;margin:0;">{{contenu_principal}}</p></div></div><div style="background:#f9fafb;padding:20px 30px;text-align:center;border-top:1px solid #e5e7eb;"><p style="color:#9ca3af;font-size:12px;margin:0;"><a href="{{lien_desabonnement}}" style="color:#9ca3af;">Se desabonner</a> | {{entreprise}}</p></div></div>',
    contenuText: 'Bonjour {{prenom}},\n\nNewsletter {{mois}} — {{entreprise}}\n\n{{contenu_principal}}\n\nSe desabonner : {{lien_desabonnement}}'
  },
  {
    nom: 'Relance facture',
    sujet: 'Rappel : Facture {{numero_facture}} en attente',
    categorie: 'relance',
    variables: ['prenom', 'entreprise', 'numero_facture', 'montant', 'date_echeance', 'lien_paiement'],
    contenuHtml: '<div style="font-family:\'Segoe UI\',Arial,sans-serif;max-width:600px;margin:0 auto;background:#ffffff;border-radius:8px;overflow:hidden;"><div style="background:#f59e0b;padding:25px 30px;"><h1 style="color:#ffffff;margin:0;font-size:22px;">Rappel de paiement</h1></div><div style="padding:30px;"><p style="color:#374151;font-size:16px;line-height:1.6;">Bonjour {{prenom}},</p><p style="color:#374151;font-size:16px;line-height:1.6;">Nous vous rappelons que la facture <strong>{{numero_facture}}</strong> d\'un montant de <strong>{{montant}}</strong> est arrivee a echeance le <strong>{{date_echeance}}</strong>.</p><div style="background:#fffbeb;border:1px solid #fde68a;border-radius:8px;padding:20px;margin:20px 0;text-align:center;"><p style="color:#92400e;font-size:18px;font-weight:700;margin:0;">{{montant}}</p><p style="color:#b45309;font-size:13px;margin:4px 0 0;">Echeance : {{date_echeance}}</p></div><div style="text-align:center;margin:25px 0;"><a href="{{lien_paiement}}" style="display:inline-block;padding:14px 32px;background:#f59e0b;color:#ffffff;text-decoration:none;border-radius:8px;font-weight:600;font-size:16px;">Regler ma facture</a></div><p style="color:#6b7280;font-size:14px;line-height:1.6;">Si le paiement a deja ete effectue, veuillez ignorer ce message.</p></div><div style="background:#f9fafb;padding:20px 30px;text-align:center;border-top:1px solid #e5e7eb;"><p style="color:#9ca3af;font-size:12px;margin:0;">{{entreprise}}</p></div></div>',
    contenuText: 'Bonjour {{prenom}},\n\nRappel : La facture {{numero_facture}} de {{montant}} est arrivee a echeance le {{date_echeance}}.\n\nRegler : {{lien_paiement}}\n\nSi deja paye, ignorez ce message.\n\n{{entreprise}}'
  },
  {
    nom: 'Relance devis',
    sujet: 'Votre devis {{numero_devis}} — toujours interesse ?',
    categorie: 'relance',
    variables: ['prenom', 'entreprise', 'numero_devis', 'montant', 'date_devis', 'lien_devis'],
    contenuHtml: '<div style="font-family:\'Segoe UI\',Arial,sans-serif;max-width:600px;margin:0 auto;background:#ffffff;border-radius:8px;overflow:hidden;"><div style="background:#8b5cf6;padding:25px 30px;"><h1 style="color:#ffffff;margin:0;font-size:22px;">Suivi de votre devis</h1></div><div style="padding:30px;"><p style="color:#374151;font-size:16px;line-height:1.6;">Bonjour {{prenom}},</p><p style="color:#374151;font-size:16px;line-height:1.6;">Nous revenons vers vous concernant le devis <strong>{{numero_devis}}</strong> du <strong>{{date_devis}}</strong> d\'un montant de <strong>{{montant}}</strong>.</p><p style="color:#374151;font-size:16px;line-height:1.6;">Nous restons a votre disposition pour toute question ou modification.</p><div style="text-align:center;margin:25px 0;"><a href="{{lien_devis}}" style="display:inline-block;padding:14px 32px;background:#8b5cf6;color:#ffffff;text-decoration:none;border-radius:8px;font-weight:600;font-size:16px;">Voir le devis</a></div></div><div style="background:#f9fafb;padding:20px 30px;text-align:center;border-top:1px solid #e5e7eb;"><p style="color:#9ca3af;font-size:12px;margin:0;">{{entreprise}}</p></div></div>',
    contenuText: 'Bonjour {{prenom}},\n\nSuivi de votre devis {{numero_devis}} du {{date_devis}} ({{montant}}).\n\nVoir le devis : {{lien_devis}}\n\nCordialement,\n{{entreprise}}'
  },
  {
    nom: 'Promotion',
    sujet: '{{titre_promo}} — Offre speciale {{entreprise}}',
    categorie: 'promotion',
    variables: ['prenom', 'entreprise', 'titre_promo', 'description_promo', 'code_promo', 'date_fin', 'lien_offre', 'lien_desabonnement'],
    contenuHtml: '<div style="font-family:\'Segoe UI\',Arial,sans-serif;max-width:600px;margin:0 auto;background:#ffffff;border-radius:8px;overflow:hidden;"><div style="background:linear-gradient(135deg,#059669,#047857);padding:35px 30px;text-align:center;"><h1 style="color:#ffffff;margin:0;font-size:26px;">{{titre_promo}}</h1><p style="color:#a7f3d0;margin:8px 0 0;font-size:14px;">Offre limitee</p></div><div style="padding:30px;"><p style="color:#374151;font-size:16px;line-height:1.6;">Bonjour {{prenom}},</p><p style="color:#374151;font-size:16px;line-height:1.6;">{{description_promo}}</p><div style="background:#ecfdf5;border:2px dashed #059669;border-radius:8px;padding:20px;margin:20px 0;text-align:center;"><p style="color:#065f46;font-size:13px;margin:0 0 5px;">Votre code promo</p><p style="color:#059669;font-size:28px;font-weight:700;margin:0;letter-spacing:3px;">{{code_promo}}</p><p style="color:#6b7280;font-size:12px;margin:5px 0 0;">Valable jusqu\'au {{date_fin}}</p></div><div style="text-align:center;margin:25px 0;"><a href="{{lien_offre}}" style="display:inline-block;padding:14px 32px;background:#059669;color:#ffffff;text-decoration:none;border-radius:8px;font-weight:600;font-size:16px;">Profiter de l\'offre</a></div></div><div style="background:#f9fafb;padding:20px 30px;text-align:center;border-top:1px solid #e5e7eb;"><p style="color:#9ca3af;font-size:12px;margin:0;"><a href="{{lien_desabonnement}}" style="color:#9ca3af;">Se desabonner</a> | {{entreprise}}</p></div></div>',
    contenuText: 'Bonjour {{prenom}},\n\n{{titre_promo}}\n\n{{description_promo}}\n\nCode promo : {{code_promo}} (valable jusqu\'au {{date_fin}})\n\nProfiter de l\'offre : {{lien_offre}}\n\nSe desabonner : {{lien_desabonnement}}\n{{entreprise}}'
  },
  {
    nom: 'Confirmation de commande',
    sujet: 'Confirmation de votre commande {{numero_commande}}',
    categorie: 'transactionnel',
    variables: ['prenom', 'entreprise', 'numero_commande', 'montant', 'date_commande', 'lien_suivi'],
    contenuHtml: '<div style="font-family:\'Segoe UI\',Arial,sans-serif;max-width:600px;margin:0 auto;background:#ffffff;border-radius:8px;overflow:hidden;"><div style="background:#2563eb;padding:30px;text-align:center;"><div style="width:60px;height:60px;background:rgba(255,255,255,0.2);border-radius:50%;margin:0 auto 15px;display:flex;align-items:center;justify-content:center;"><span style="font-size:30px;">&#10003;</span></div><h1 style="color:#ffffff;margin:0;font-size:24px;">Commande confirmee</h1></div><div style="padding:30px;"><p style="color:#374151;font-size:16px;line-height:1.6;">Bonjour {{prenom}},</p><p style="color:#374151;font-size:16px;line-height:1.6;">Votre commande <strong>{{numero_commande}}</strong> du <strong>{{date_commande}}</strong> a bien ete enregistree.</p><div style="background:#eff6ff;border:1px solid #bfdbfe;border-radius:8px;padding:20px;margin:20px 0;"><table style="width:100%;border-collapse:collapse;"><tr><td style="color:#6b7280;font-size:14px;padding:4px 0;">Commande</td><td style="color:#1e293b;font-size:14px;font-weight:600;text-align:right;">{{numero_commande}}</td></tr><tr><td style="color:#6b7280;font-size:14px;padding:4px 0;">Montant</td><td style="color:#1e293b;font-size:14px;font-weight:600;text-align:right;">{{montant}}</td></tr><tr><td style="color:#6b7280;font-size:14px;padding:4px 0;">Date</td><td style="color:#1e293b;font-size:14px;text-align:right;">{{date_commande}}</td></tr></table></div><div style="text-align:center;margin:25px 0;"><a href="{{lien_suivi}}" style="display:inline-block;padding:14px 32px;background:#2563eb;color:#ffffff;text-decoration:none;border-radius:8px;font-weight:600;font-size:16px;">Suivre ma commande</a></div></div><div style="background:#f9fafb;padding:20px 30px;text-align:center;border-top:1px solid #e5e7eb;"><p style="color:#9ca3af;font-size:12px;margin:0;">{{entreprise}}</p></div></div>',
    contenuText: 'Bonjour {{prenom}},\n\nVotre commande {{numero_commande}} du {{date_commande}} est confirmee.\nMontant : {{montant}}\n\nSuivre : {{lien_suivi}}\n\n{{entreprise}}'
  }
];

// Build INSERT SQL with multiple VALUES
const values = templates.map(t => {
  const vars = t.variables.map(v => esc(v)).join(',');
  return `(gen_random_uuid()::uuid, ${esc(tenantId)}, ${esc(t.nom)}, ${esc(t.sujet)}, ${esc(t.contenuHtml)}, ${esc(t.contenuText)}, ARRAY[${vars}], ${esc(t.categorie)}, NOW(), NOW())`;
}).join(',\n');

// Check if templates already exist for this tenant
const checkSql = `SELECT COUNT(*)::int AS count FROM email_templates WHERE tenant_id = ${esc(tenantId)}`;

return { checkSql, insertSql: `INSERT INTO email_templates (id, tenant_id, nom, sujet, contenu_html, contenu_text, variables, categorie, created_at, updated_at) VALUES ${values} RETURNING id, nom, categorie`, templateCount: templates.length };

const rows = $input.all();
const count = rows[0]?.json?.count ?? rows[0]?.json?.Count ?? 0;
const existingCount = typeof count === 'string' ? parseInt(count, 10) : count;

// Si des templates existent deja, ne pas re-seeder
if (existingCount > 0) {
  return { skip: true, message: `${existingCount} templates existent deja`, existingCount };
}

return { skip: false, existingCount: 0 };

const rows = $input.all();
const inserted = rows.filter(r => r.json?.id).map(r => ({ id: r.json.id, nom: r.json.nom, categorie: r.json.categorie }));

return {
  success: true,
  message: `${inserted.length} templates crees avec succes`,
  templates: inserted
};

const data = $('05. Deja Seede?').first().json;
return {
  success: true,
  message: data.message || 'Templates deja presents',
  skipped: true,
  existingCount: data.existingCount || 0
};
